-- Create a stored procedure with input parameters and error handling
IF OBJECT_ID('dbo.usp_GetCustomersByCountry', 'P') IS NOT NULL
    DROP PROCEDURE dbo.usp_GetCustomersByCountry;
GO

CREATE PROCEDURE dbo.usp_GetCustomersByCountry
    @CountryCode NVARCHAR(10),
    @MaxRows     INT = 100
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        IF @CountryCode IS NULL OR LEN(TRIM(@CountryCode)) = 0
        BEGIN
            RAISERROR('CountryCode parameter cannot be null or empty.', 16, 1);
            RETURN;
        END

        SELECT TOP (@MaxRows)
            CustomerID,
            Username,
            FullName,
            CountryCode,
            LanguageCode
        FROM dbo.CustomerProfiles
        WHERE CountryCode = @CountryCode
        ORDER BY FullName;
    END TRY
    BEGIN CATCH
        DECLARE @ErrMsg  NVARCHAR(4000) = ERROR_MESSAGE();
        DECLARE @ErrSev  INT            = ERROR_SEVERITY();
        DECLARE @ErrSte  INT            = ERROR_STATE();
        RAISERROR(@ErrMsg, @ErrSev, @ErrSte);
    END CATCH
END;
GO

-- Execute the procedure
EXEC dbo.usp_GetCustomersByCountry @CountryCode = 'US';
EXEC dbo.usp_GetCustomersByCountry @CountryCode = 'GB', @MaxRows = 10;

