-- PostgreSQL uses CREATE PROCEDURE (PG 11+) or CREATE FUNCTION for routines
-- Drop if exists first
DROP PROCEDURE IF EXISTS get_customers_by_country(VARCHAR, INT);

CREATE OR REPLACE PROCEDURE get_customers_by_country(
    p_country_code  VARCHAR(10),
    p_max_rows      INT DEFAULT 100
)
LANGUAGE plpgsql
AS $$
DECLARE
    v_count INT;
BEGIN
    IF p_country_code IS NULL OR trim(p_country_code) = '' THEN
        RAISE EXCEPTION 'country_code parameter cannot be null or empty'
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    -- PostgreSQL procedures cannot return result sets directly.
    -- Use a function with RETURNS TABLE for query results (see table_valued_functions).
    -- Procedures are suited for DML operations, transaction control, and side effects.
    SELECT COUNT(*) INTO v_count
    FROM public.customer_profiles
    WHERE country_code = p_country_code::CHAR;

    RAISE NOTICE 'Found % customers for country: %', v_count, p_country_code;
END;
$$;

-- Call the procedure using CALL
CALL get_customers_by_country('US');
CALL get_customers_by_country('GB', 10);

-- For returning rows, use a function with RETURNS TABLE instead:
CREATE OR REPLACE FUNCTION get_customers_by_country_fn(
    p_country_code  VARCHAR(10),
    p_max_rows      INT DEFAULT 100
)
RETURNS TABLE (
    customer_id   INT,
    username      VARCHAR,
    full_name     VARCHAR,
    country_code  CHAR
)
LANGUAGE plpgsql
AS $$
BEGIN
    IF p_country_code IS NULL OR trim(p_country_code) = '' THEN
        RAISE EXCEPTION 'country_code cannot be null or empty'
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    RETURN QUERY
    SELECT
        cp.customer_id,
        cp.username,
        cp.full_name,
        cp.country_code
    FROM public.customer_profiles cp
    WHERE cp.country_code = p_country_code::CHAR
    ORDER BY cp.full_name
    LIMIT p_max_rows;
END;
$$;

-- Call the function in a SELECT
SELECT * FROM get_customers_by_country_fn('US');

