-- Create a procedure with OUTPUT parameters and a RETURN value
IF OBJECT_ID('dbo.usp_GetCustomerStats', 'P') IS NOT NULL
    DROP PROCEDURE dbo.usp_GetCustomerStats;
GO

CREATE PROCEDURE dbo.usp_GetCustomerStats
    @CountryCode    NVARCHAR(10),
    @CustomerCount  INT OUTPUT,
    @LatestUsername NVARCHAR(100) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    SELECT
        @CustomerCount  = COUNT(*),
        @LatestUsername = MAX(Username)
    FROM dbo.CustomerProfiles
    WHERE CountryCode = @CountryCode;

    -- RETURN passes an integer status code back to the caller
    IF @CustomerCount = 0
        RETURN 1;  -- 1 = no rows found

    RETURN 0;     -- 0 = success
END;
GO

-- Calling the procedure and capturing OUTPUT parameters
DECLARE @Count   INT;
DECLARE @Latest  NVARCHAR(100);
DECLARE @RetVal  INT;

EXEC @RetVal = dbo.usp_GetCustomerStats
    @CountryCode    = 'US',
    @CustomerCount  = @Count  OUTPUT,
    @LatestUsername = @Latest OUTPUT;

SELECT
    @Count  AS CustomerCount,
    @Latest AS LatestUsername,
    @RetVal AS ReturnValue;

