-- PostgreSQL uses OUT parameters in functions
-- The function returns a record containing all OUT parameter values
DROP FUNCTION IF EXISTS get_customer_stats(VARCHAR);

CREATE OR REPLACE FUNCTION get_customer_stats(
    p_country_code    VARCHAR(10),
    OUT p_customer_count  INT,
    OUT p_latest_username VARCHAR(100)
)
LANGUAGE plpgsql
AS $$
BEGIN
    SELECT
        COUNT(*)::INT,
        MAX(username)
    INTO p_customer_count, p_latest_username
    FROM public.customer_profiles
    WHERE country_code = p_country_code::CHAR;

    -- COUNT always returns a row, so p_customer_count will be 0 (not NULL) when no rows match
END;
$$;

-- Call the function and get all OUT parameters as columns
SELECT * FROM get_customer_stats('US');

-- Or capture individual output values into variables (inside plpgsql)
DO $$
DECLARE
    v_count    INT;
    v_latest   VARCHAR(100);
BEGIN
    SELECT p_customer_count, p_latest_username
    INTO v_count, v_latest
    FROM get_customer_stats('US');

    RAISE NOTICE 'Count: %, Latest: %', v_count, v_latest;
END;
$$;

-- Returning a status code: use a scalar RETURNS INT function
CREATE OR REPLACE FUNCTION get_customer_stats_with_status(
    p_country_code    VARCHAR(10),
    OUT p_customer_count  INT,
    OUT p_latest_username VARCHAR(100),
    OUT p_status_code     INT
)
LANGUAGE plpgsql
AS $$
BEGIN
    SELECT COUNT(*)::INT, MAX(username)
    INTO p_customer_count, p_latest_username
    FROM public.customer_profiles
    WHERE country_code = p_country_code::CHAR;

    p_status_code := CASE WHEN p_customer_count = 0 THEN 1 ELSE 0 END;
END;
$$;

SELECT * FROM get_customer_stats_with_status('US');

