-- Create a scalar function that formats a full name
IF OBJECT_ID('dbo.fn_FormatFullName', 'FN') IS NOT NULL
    DROP FUNCTION dbo.fn_FormatFullName;
GO

CREATE FUNCTION dbo.fn_FormatFullName
(
    @FirstName NVARCHAR(100),
    @LastName  NVARCHAR(100),
    @Format    NVARCHAR(20) = 'LAST_FIRST'
)
RETURNS NVARCHAR(205)
AS
BEGIN
    DECLARE @Result NVARCHAR(205);

    IF @Format = 'LAST_FIRST'
        SET @Result = @LastName + ', ' + @FirstName;
    ELSE IF @Format = 'FIRST_LAST'
        SET @Result = @FirstName + ' ' + @LastName;
    ELSE
        SET @Result = @FirstName + ' ' + @LastName;

    RETURN @Result;
END;
GO

-- Use the function in a SELECT
SELECT
    dbo.fn_FormatFullName('Jane', 'Smith', 'LAST_FIRST')  AS LastFirst,
    dbo.fn_FormatFullName('Jane', 'Smith', 'FIRST_LAST')  AS FirstLast;

-- Use in a table query (must prefix with schema)
SELECT
    CustomerID,
    dbo.fn_FormatFullName(
        LEFT(FullName, CHARINDEX(' ', FullName) - 1),
        RIGHT(FullName, LEN(FullName) - CHARINDEX(' ', FullName))
    ) AS FormattedName
FROM dbo.CustomerProfiles;
